    <line x1="60" y1="380" x2="660" y2="380" stroke="#3f3f46" stroke-width="1.5"/>
    <line x1="335" y1="80" x2="335" y2="380" stroke="#27272a" stroke-width="1" stroke-dasharray="4 4"/>
    <rect x="90" y="236" width="70" height="144" rx="6" fill="#52525b"/>
    <text x="125" y="228" fill="#e4e4e7" font-size="14" text-anchor="middle" font-weight="700">61,100</text>
    <text x="125" y="400" fill="#a1a1aa" font-size="12" text-anchor="middle">Prior 2 quarters combined</text>
